begin
wwv_flow_imp_shared.create_list_of_values(
 p_id=>wwv_flow_imp.id(11442466770891942)
,p_lov_name=>'APPOINTMENTS_LOV'
,p_static_id=>'appointments-lov'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT TO_CHAR(a.APPOINTMENT_DATE, ''DD-MON-YYYY'') || '' - '' || p.FULL_NAME || '' ('' || a.REASON_FOR_VISIT || '')'' AS display_value,',
'       a.APPOINTMENT_ID AS return_value',
'FROM APPOINTMENTS a',
'JOIN PATIENTS p ON p.PATIENT_ID = a.PATIENT_ID',
'ORDER BY a.APPOINTMENT_DATE DESC'))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_return_column_name=>'RETURN_VALUE'
