wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(10134954985242946)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Get Appointment Context'
,p_static_id=>'get-appointment-context'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  SELECT PATIENT_ID, DOCTOR_ID INTO :P20_PATIENT_ID, :P20_DOCTOR_ID ',
'  FROM APPOINTMENTS WHERE APPOINTMENT_ID = :P20_APPOINTMENT_ID;',
'  ',
'  BEGIN',
'    SELECT VISIT_ID INTO :P20_VISIT_ID FROM PATIENT_VISITS WHERE APPOINTMENT_ID = :P20_APPOINTMENT_ID;',
'  EXCEPTION WHEN NO_DATA_FOUND THEN :P20_VISIT_ID := NULL;',
'  END;',
'  ',
'  IF :P20_VISIT_ID IS NOT NULL THEN',
'    BEGIN',
'      SELECT PRESCRIPTION_ID INTO :P20_PRESCRIPTION_ID FROM PRESCRIPTIONS WHERE VISIT_ID = :P20_VISIT_ID;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN :P20_PRESCRIPTION_ID := NULL;',
'    END;',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>10134954985242946
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(10211043229276225)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Insert Prescription'
,p_static_id=>'insert-prescription'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_new_id NUMBER;',
'BEGIN',
'  INSERT INTO PRESCRIPTIONS (VISIT_ID, PATIENT_ID, DOCTOR_ID, PRESCRIPTION_DATE)',
'  VALUES (:P20_VISIT_ID, :P20_PATIENT_ID, :P20_DOCTOR_ID, SYSDATE)',
'  RETURNING PRESCRIPTION_ID INTO v_new_id;',
'  :P20_PRESCRIPTION_ID := v_new_id;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'CREATE_PRESCRIPTION'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_internal_uid=>10211043229276225
);
