wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(10210766114276222)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Save Visit'
,p_static_id=>'save-visit'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  IF :P20_VISIT_ID IS NULL THEN',
'    INSERT INTO PATIENT_VISITS (APPOINTMENT_ID, PATIENT_ID, DOCTOR_ID, VISIT_DATE, SYMPTOMS, DIAGNOSIS, NOTES, FOLLOW_UP_DATE)',
'    VALUES (:P20_APPOINTMENT_ID, :P20_PATIENT_ID, :P20_DOCTOR_ID, SYSDATE, :P20_SYMPTOMS, :P20_DIAGNOSIS, :P20_NOTES, :P20_FOLLOW_UP_DATE)',
'    RETURNING VISIT_ID INTO :P20_VISIT_ID;',
'  ELSE',
'    UPDATE PATIENT_VISITS SET SYMPTOMS = :P20_SYMPTOMS, DIAGNOSIS = :P20_DIAGNOSIS, NOTES = :P20_NOTES, FOLLOW_UP_DATE = :P20_FOLLOW_UP_DATE WHERE VISIT_ID = :P20_VISIT_ID;',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'SAVE_VISIT'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_internal_uid=>10210766114276222
);
end;
