,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT a.APPOINTMENT_ID, p.FULL_NAME AS PATIENT_NAME, d.FULL_NAME AS DOCTOR_NAME,',
'       dept.DEPARTMENT_NAME, a.APPOINTMENT_DATE, a.APPOINTMENT_TIME,',
'       s.STATUS_NAME, a.REASON_FOR_VISIT',
'FROM APPOINTMENTS a',
'JOIN PATIENTS p ON p.PATIENT_ID = a.PATIENT_ID',
'JOIN DOCTORS d ON d.DOCTOR_ID = a.DOCTOR_ID',
'JOIN DEPARTMENTS dept ON dept.DEPARTMENT_ID = d.DEPARTMENT_ID',
'JOIN APPOINTMENT_STATUSES s ON s.STATUS_ID = a.STATUS_ID',
'WHERE (:P23_DATE_FROM IS NULL OR a.APPOINTMENT_DATE >= TO_DATE(:P23_DATE_FROM))',
'  AND (:P23_DATE_TO IS NULL OR a.APPOINTMENT_DATE <= TO_DATE(:P23_DATE_TO))',
'ORDER BY a.APPOINTMENT_DATE DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P23_DATE_FROM,P23_DATE_TO'
,p_prn_content_disposition=>'ATTACHMENT'
